bool esSuficientementeDisperso(vector<int>& numeros, int K) {
    // Caso base: si el vector tiene un solo elemento
    if (numeros.size() == 1) return true;

    // Calcular la diferencia entre el primer y último elemento
    int diferencia = numeros.back() - numeros.front();

    // Verificar si la diferencia es suficiente
    if (diferencia < K) return false;

    // Dividir el vector en dos mitades
    int mitad = numeros.size() / 2;
    vector<int> primeraMitad(numeros.begin(), numeros.begin() + mitad);
    vector<int> segundaMitad(numeros.begin() + mitad, numeros.end());

    // Aplicar recursión a cada mitad
    return esSuficientementeDisperso(primeraMitad, K) && esSuficientementeDisperso(segundaMitad, K);
}
